#include <bits/stdc++.h>
#define R register
using namespace std;

const int N=1e5+10,M=350,B=330;

int n,m,a[N],cl[N],h[M][M],bl[N][M],br[N][M],sl[M][M],sr[M][M],c[N],b[N][M];
long long f[M][M];

inline int rd(){
	int r=0;char ch=getchar();
	while(ch<'0' || '9'<ch) ch=getchar();
	while('0'<=ch && ch<='9') r=(r<<3)+(r<<1)+ch-'0',ch=getchar();
	return r;
}

inline void add(int x,int k){
    for(;x<=n;x+=(x&(-x))) c[x]+=k;
}

inline int ask(int x){
    int res=0;
    for(;x;x-=(x&(-x))) res+=c[x];
    return res;
}

inline void del(int x){
	for(;x<=n && c[x];x+=(x&(-x))) c[x]=0;
}

inline bool cmp(int x,int y){
    return a[x]<a[y];
}

long long query(int l,int r){
    int p=cl[l],q=cl[r];
    long long res=0;
    if(p==q)
        return b[l][r-l+1];
    res=f[p+1][q-1]+sr[p][l-(p-1)*B]+sl[q][r-(q-1)*B];
//    printf("%d %d\n",sr[p][l-(p-1)*B],sl[q][r-(q-1)*B]);
    for(int i=l;cl[i]==p;i++) res+=br[i][q-1];
    for(int i=r;cl[i]==q;i--) res+=bl[i][p+1];
    for(int i=1,j=1,cnt=0;h[p][i];i++){
        while(h[q][j] && a[h[p][i]]>a[h[q][j]]){
            cnt+=(h[q][j]<=r);
            j++;
        }
        if(h[p][i]>=l) res+=cnt;
    }
    return res;
}

int main(){
	 // freopen("qwq.in","r",stdin);
	 // freopen("qwq.out","w",stdout);
	int st=clock();
    n=rd(),m=rd();
    for(R int i=1;i<=n;++i){
        a[i]=rd();
        cl[i]=(i-1)/B+1;
    }
    for(R int i=1;i<=cl[n];++i){
        int l=(i-1)*B,r=min(n,i*B);
        for(R int j=l+1;j<=r;++j){
            add(a[j],1);
            sl[i][j-l]=sl[i][j-l-1]+j-l-ask(a[j]);
            h[i][j-l]=j;
        }
        for(R int j=1;j<=n;++j)
            c[j]+=c[j-(j&(-j))];
        for(R int j=r;j>l;--j)
            sr[i][j-l]=sr[i][j+1-l]+l-j+c[a[j]]+sl[i][j-l]-sl[i][j-l-1];
        sort(h[i]+1,h[i]+r-l+1,cmp);
        f[i][i]=sl[i][r-l];
        for(R int j=1;j<=l;++j){
            br[j][i]=c[a[j]];
            f[cl[j]][i]+=c[a[j]];
        }
        for(R int j=r+1;j<=n;++j)
            bl[j][i]=r-l-c[a[j]];
        for(R int j=1;j<=n;++j)
        	c[j]=0;
    }
    for(R int i=1;i<=cl[n];++i)
        for(R int l=1,r;l+i-1<=cl[n];++l){
            r=l+i-1;
            f[l][r]=f[l][r-1]+f[l+1][r]-f[l+1][r-1]+f[l][r];
        }
    for(R int i=1;i<=n;++i){
        for(R int j=cl[i]+1;j<=cl[n];++j)
            br[i][j]+=br[i][j-1];
        for(R int j=cl[i]-1;j;--j)
            bl[i][j]+=bl[i][j+1];
    }
    for(R int i=2;i<=B;++i)
        for(R int j=1;j+i-1<=n;++j)
            b[j][i]=b[j][i-1]+b[j+1][i-1]-b[j+1][i-2]+(a[j]>a[j+i-1]);
    // printf("%d\n",clock()-st);
//    puts("OK");
    long long la=0;
    while(m--){
        long long l,r;
        scanf("%lld%lld",&l,&r);
       l^=la,r^=la;
        if(l>r) swap(l,r);
        if(l<1 || l>n || r<1 || r>n){
        	puts("Errow");
			break;
		}
		la=query(l,r);
        printf("%lld\n",la);
    }
    return 0;
}
